import React, { useState, useEffect, useRef } from 'react';
import {
  ShoppingBag, ShoppingCart, LogOut, User, MapPin, Package,
  Plus, Trash2, ArrowRight, Edit3, Check, X,
  ChevronRight, TrendingUp, Zap, Home, Briefcase, Star
} from 'lucide-react';
import { authAPI, addressAPI } from '/home/sidhu/Desktop/ECommerceAPI/frontend/src/api.js';

// ─── Add Address Modal ─────────────────────────────────────────────
const AddressModal = ({ onClose, onSave, saving }) => {
  const [form, setForm] = useState({
    label: 'Home', addressLine1: '', addressLine2: '',
    city: '', state: '', postalCode: '', country: 'India', isDefault: false
  });
  const [errors, setErrors] = useState({});
  const firstRef = useRef(null);

  useEffect(() => {
    firstRef.current?.focus();
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = ''; };
  }, []);

  const set = (k, v) => { setForm(p => ({ ...p, [k]: v })); setErrors(p => ({ ...p, [k]: '' })); };

  const validate = () => {
    const e = {};
    if (!form.addressLine1.trim()) e.addressLine1 = 'Address line 1 is required';
    if (!form.city.trim()) e.city = 'City is required';
    if (!form.postalCode.trim()) e.postalCode = 'Postal code is required';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = () => { if (validate()) onSave(form); };

  const labelOptions = [
    { value: 'Home',   icon: Home,      color: 'text-teal-600',   bg: 'bg-teal-50 border-teal-200' },
    { value: 'Work',   icon: Briefcase, color: 'text-violet-600', bg: 'bg-violet-50 border-violet-200' },
    { value: 'Other',  icon: MapPin,    color: 'text-orange-600', bg: 'bg-orange-50 border-orange-200' },
  ];

  const Field = ({ k, label, placeholder, required, half }) => (
    <div className={half ? '' : 'col-span-2'}>
      <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">
        {label} {required && <span className="text-red-400">*</span>}
      </label>
      <input
        value={form[k]}
        onChange={e => set(k, e.target.value)}
        placeholder={placeholder}
        className={`w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none focus:ring-4 placeholder-slate-300
          ${errors[k]
            ? 'border-2 border-red-300 bg-red-50 focus:border-red-400 focus:ring-red-50'
            : 'border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-teal-50 hover:border-gray-200'
          }`}
      />
      {errors[k] && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors[k]}</p>}
    </div>
  );

  return (
    <div
      className="fixed inset-0 z-[100] flex items-center justify-center p-4"
      style={{ background: 'rgba(15,23,42,0.45)', backdropFilter: 'blur(6px)', animation: 'fadeIn .2s ease both' }}
      onClick={e => e.target === e.currentTarget && onClose()}
    >
      <div
        className="w-full max-w-lg bg-white rounded-[32px] overflow-hidden shadow-2xl"
        style={{ animation: 'modalSlide .35s cubic-bezier(0.34,1.56,0.64,1) both', maxHeight: '90vh' }}
      >
        <style>{`
          @keyframes fadeIn{from{opacity:0}to{opacity:1}}
          @keyframes modalSlide{from{opacity:0;transform:scale(0.92) translateY(20px)}to{opacity:1;transform:scale(1) translateY(0)}}
        `}</style>

        {/* Modal Header */}
        <div className="relative px-7 py-6 bg-gradient-to-r from-teal-500 to-cyan-600 overflow-hidden">
          <div className="absolute inset-0 opacity-10"
            style={{ backgroundImage:'linear-gradient(rgba(255,255,255,.6) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.6) 1px,transparent 1px)', backgroundSize:'32px 32px' }} />
          <div className="absolute right-0 top-0 w-48 h-48 rounded-full opacity-15"
            style={{ background:'white', filter:'blur(40px)', transform:'translate(30%,-30%)' }} />
          <div className="relative z-10 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-11 h-11 rounded-2xl flex items-center justify-center"
                style={{ background: 'rgba(255,255,255,0.22)', border: '1px solid rgba(255,255,255,0.3)' }}>
                <MapPin className="w-5 h-5 text-white" />
              </div>
              <div>
                <h3 className="text-white font-black text-lg leading-none">Add New Address</h3>
                <p className="text-teal-100 text-xs mt-0.5">Save for faster checkout</p>
              </div>
            </div>
            <button onClick={onClose}
              className="w-9 h-9 flex items-center justify-center rounded-xl text-white/70 hover:text-white hover:bg-white/15 transition-all">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Scrollable body */}
        <div className="overflow-y-auto px-7 py-6 space-y-5" style={{ maxHeight: 'calc(90vh - 160px)' }}>

          {/* Address type label picker */}
          <div>
            <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2.5">Address Type</label>
            <div className="flex gap-2">
              {labelOptions.map(opt => {
                const Icon = opt.icon;
                const active = form.label === opt.value;
                return (
                  <button key={opt.value} type="button" onClick={() => set('label', opt.value)}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-2xl text-sm font-bold border-2 transition-all active:scale-95 ${
                      active ? `${opt.bg} ${opt.color} scale-[1.02] shadow-sm` : 'bg-white border-gray-100 text-slate-500 hover:border-gray-200'
                    }`}>
                    <Icon className="w-4 h-4" />
                    {opt.value}
                    {active && <Check className="w-3.5 h-3.5" />}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Fields grid */}
          <div className="grid grid-cols-2 gap-4">
            {/* Address Line 1 — full width */}
            <div className="col-span-2">
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">
                Address Line 1 <span className="text-red-400">*</span>
              </label>
              <input ref={firstRef}
                value={form.addressLine1}
                onChange={e => set('addressLine1', e.target.value)}
                placeholder="House / Flat no., Building name, Street"
                className={`w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none focus:ring-4 placeholder-slate-300
                  ${errors.addressLine1 ? 'border-2 border-red-300 bg-red-50 focus:border-red-400 focus:ring-red-50' : 'border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-teal-50 hover:border-gray-200'}`}
              />
              {errors.addressLine1 && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors.addressLine1}</p>}
            </div>

            {/* Address Line 2 — full width */}
            <div className="col-span-2">
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">Address Line 2 <span className="text-slate-300 font-medium normal-case">(optional)</span></label>
              <input value={form.addressLine2} onChange={e => set('addressLine2', e.target.value)}
                placeholder="Landmark, Area, Colony"
                className="w-full px-4 py-3 rounded-2xl text-sm font-medium border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-4 focus:ring-teal-50 focus:outline-none hover:border-gray-200 transition-all placeholder-slate-300" />
            </div>

            {/* City */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">City <span className="text-red-400">*</span></label>
              <input value={form.city} onChange={e => set('city', e.target.value)}
                placeholder="e.g. Mumbai"
                className={`w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none focus:ring-4 placeholder-slate-300
                  ${errors.city ? 'border-2 border-red-300 bg-red-50 focus:border-red-400 focus:ring-red-50' : 'border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-teal-50 hover:border-gray-200'}`} />
              {errors.city && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors.city}</p>}
            </div>

            {/* State */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">State</label>
              <input value={form.state} onChange={e => set('state', e.target.value)}
                placeholder="e.g. Maharashtra"
                className="w-full px-4 py-3 rounded-2xl text-sm font-medium border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-4 focus:ring-teal-50 focus:outline-none hover:border-gray-200 transition-all placeholder-slate-300" />
            </div>

            {/* Postal Code */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">Postal Code <span className="text-red-400">*</span></label>
              <input value={form.postalCode} onChange={e => set('postalCode', e.target.value)}
                placeholder="e.g. 400001" maxLength={10}
                className={`w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none focus:ring-4 placeholder-slate-300
                  ${errors.postalCode ? 'border-2 border-red-300 bg-red-50 focus:border-red-400 focus:ring-red-50' : 'border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-teal-50 hover:border-gray-200'}`} />
              {errors.postalCode && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors.postalCode}</p>}
            </div>

            {/* Country */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">Country</label>
              <select value={form.country} onChange={e => set('country', e.target.value)}
                className="w-full px-4 py-3 rounded-2xl text-sm font-medium border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-4 focus:ring-teal-50 focus:outline-none hover:border-gray-200 transition-all text-slate-800">
                {['India','United States','United Kingdom','Canada','Australia','Singapore','UAE','Other'].map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Set as default toggle */}
          <button type="button" onClick={() => set('isDefault', !form.isDefault)}
            className={`w-full flex items-center justify-between px-5 py-4 rounded-2xl border-2 transition-all ${
              form.isDefault ? 'border-teal-300 bg-teal-50' : 'border-gray-100 bg-white hover:border-gray-200'
            }`}>
            <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${form.isDefault ? 'bg-gradient-to-br from-teal-500 to-cyan-600' : 'bg-slate-100'}`}>
                <Star className={`w-4 h-4 ${form.isDefault ? 'text-white' : 'text-slate-400'}`} />
              </div>
              <div className="text-left">
                <p className={`text-sm font-bold ${form.isDefault ? 'text-teal-700' : 'text-slate-700'}`}>Set as Default Address</p>
                <p className="text-xs text-slate-400">Used automatically at checkout</p>
              </div>
            </div>
            {/* Toggle pill */}
            <div className={`w-12 h-6 rounded-full transition-all relative ${form.isDefault ? 'bg-gradient-to-r from-teal-500 to-cyan-600' : 'bg-gray-200'}`}>
              <div className={`absolute top-0.5 w-5 h-5 bg-white rounded-full shadow-md transition-all duration-300 ${form.isDefault ? 'left-6' : 'left-0.5'}`} />
            </div>
          </button>
        </div>

        {/* Footer actions */}
        <div className="px-7 py-5 bg-slate-50 border-t border-gray-100 flex gap-3">
          <button onClick={onClose}
            className="flex-1 py-3.5 rounded-2xl text-sm font-bold text-slate-600 bg-white border-2 border-gray-100 hover:border-gray-200 hover:bg-gray-50 active:scale-95 transition-all">
            Cancel
          </button>
          <button onClick={handleSubmit} disabled={saving}
            className="flex-1 py-3.5 rounded-2xl text-sm font-black text-white bg-gradient-to-r from-teal-500 to-cyan-600 hover:from-teal-600 hover:to-cyan-700 shadow-md hover:shadow-cyan-200/50 active:scale-95 transition-all disabled:opacity-60 flex items-center justify-center gap-2">
            {saving
              ? <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /> Saving...</>
              : <><Check className="w-4 h-4" /> Save Address</>
            }
          </button>
        </div>
      </div>
    </div>
  );
};

// ─── Design tokens — mirrors HomePage exactly ──────────────────────
const PRI = 'bg-gradient-to-r from-teal-500 to-cyan-600 hover:from-teal-600 hover:to-cyan-700 text-white font-semibold transition-all shadow-md hover:shadow-cyan-200/50 active:scale-95';

const ProfilePage = ({
  user, cart, orders, profileData, setProfileData,
  setCurrentPage, handleLogout, setError, loadOrders, loading, setLoading
}) => {
  const [editMode, setEditMode] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  const [savingProfile, setSavingProfile] = useState(false);
  const [showAddressModal, setShowAddressModal] = useState(false);
  const [savingAddress, setSavingAddress] = useState(false);

  useEffect(() => { fetchAddresses(); fetchProfile(); }, []);
  useEffect(() => { if (user) fetchOrders(); }, [user]);

  const fetchProfile = async () => {
    try {
      const res = await authAPI.getProfile();
      const d = res.data;
      setProfileData({
        fullName: d.fullName || user?.name || '',
        email: d.email || user?.email || '',
        mobile: d.mobile || user?.mobile || '',
        gender: d.gender || user?.gender || '',
        addresses: d.addresses || []
      });
    } catch {
      if (user) setProfileData({ fullName: user.name||'', email: user.email||'', mobile: user.mobile||'', gender: user.gender||'', addresses: [] });
    }
  };

  const fetchAddresses = async () => {
    try {
      let currentUserId = null;
      try { const pr = await authAPI.getProfile(); currentUserId = pr.data?.id || pr.data?.userId || pr.data?.Id; } catch {}
      let res;
      if (typeof addressAPI?.getAll === 'function') res = await addressAPI.getAll();
      else { const pr = await authAPI.getProfile(); res = { data: pr.data?.addresses || [] }; }
      const raw = Array.isArray(res.data) ? res.data : (res.data?.addresses || []);
      const filtered = currentUserId ? raw.filter(a => { const uid = a.userId||a.UserId||a.user_id||a.UserID; return uid===currentUserId||uid===String(currentUserId); }) : raw;
      const normalized = filtered.map((a, idx) => {
        const l1=a.AddressLine1||a.addressLine1||a.line1||'', l2=a.AddressLine2||a.addressLine2||a.line2||'',
              city=a.City||a.city||'', state=a.State||a.state||'',
              postal=a.PostalCode||a.postalCode||a.pincode||'', country=a.Country||a.country||'';
        return {
          id: a.Id||a.id||`addr_${Date.now()}_${idx}`,
          label: a.Label||a.label||(a.IsDefault?'Home':'Address'),
          AddressLine1:l1, AddressLine2:l2, City:city, State:state, PostalCode:postal, Country:country,
          IsDefault: !!(a.IsDefault||a.isDefault),
          address: [l1,l2,city,state,postal,country].filter(Boolean).join(', '),
          userId: a.userId||a.UserId||a.user_id||currentUserId
        };
      });
      setProfileData(prev => ({ ...prev, addresses: normalized }));
    } catch { setProfileData(prev => ({ ...prev, addresses: [] })); }
  };

  const handleSaveProfile = async () => {
    try {
      setSavingProfile(true); setError('');
      if (typeof authAPI.updateProfile === 'function')
        await authAPI.updateProfile({ fullName: profileData.fullName, mobile: profileData.mobile, gender: profileData.gender });
      const u = JSON.parse(sessionStorage.getItem('user') || '{}');
      sessionStorage.setItem('user', JSON.stringify({ ...u, fullName: profileData.fullName, mobile: profileData.mobile, gender: profileData.gender }));
      setEditMode(false);
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Failed to update profile.');
    } finally { setSavingProfile(false); }
  };

  const fetchOrders = async () => { try { await loadOrders(); } catch {} };

  const handleSaveAddress = async (form) => {
    try {
      setSavingAddress(true);
      const u = JSON.parse(sessionStorage.getItem('user') || '{}');
      const userId = u.id || u.userId || u.Id;
      if (!userId) { setError('User ID not found. Please re-login.'); return; }
      await addressAPI.add({ userId, ...form });
      await fetchAddresses();
      setShowAddressModal(false);
    } catch (err) {
      setError(err?.response?.data?.message || err.message || 'Failed to add address');
    } finally { setSavingAddress(false); }
  };

  const removeAddress = async (id) => {
    try { await addressAPI.remove(id); await fetchAddresses(); }
    catch { setError('Failed to delete address'); }
  };

  const tabs = [
    { id:'profile',   label:'Profile',   icon: User },
    { id:'addresses', label:'Addresses', icon: MapPin },
    { id:'orders',    label:'Orders',    icon: Package },
  ];

  const displayName = profileData.fullName || user?.fullName || user?.name || 'User';
  const initials = displayName.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
  const totalSpent = orders.reduce((s,o) => s + (o.totalAmount||0), 0);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans selection:bg-teal-100 selection:text-teal-900">
      <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap" rel="stylesheet" />
      <style>{`body{font-family:'Outfit',sans-serif} @keyframes fadeIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}`}</style>

      {/* ── NAV ─────────────────────────────────────────────────── */}
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          {/* Logo */}
          <div className="flex items-center gap-2.5 group cursor-pointer" onClick={() => setCurrentPage('products')}>
            <div className="bg-gradient-to-br from-teal-500 to-cyan-600 p-2 rounded-xl group-hover:rotate-12 transition-transform duration-300">
              <ShoppingBag className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl font-black bg-clip-text text-transparent bg-gradient-to-r from-teal-600 to-cyan-700 tracking-tight">ShopAI</span>
          </div>

          {/* Nav links */}
          <div className="hidden md:flex items-center gap-1">
            {[
              { label:'Shop', page:'products' },
              { label:'Orders', page:'orders' },
            ].map(n => (
              <button key={n.page} onClick={() => setCurrentPage(n.page)}
                className="text-sm font-bold text-slate-500 hover:text-teal-600 hover:bg-teal-50 px-4 py-2 rounded-xl transition-all">
                {n.label}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-3">
            <button onClick={() => setCurrentPage('cart')}
              className="relative p-2.5 text-slate-500 hover:text-teal-600 hover:bg-teal-50 rounded-xl transition-all">
              <ShoppingCart className="w-6 h-6" />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 w-5 h-5 bg-orange-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">{cart.length}</span>
              )}
            </button>
            <button onClick={handleLogout}
              className="hidden sm:flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-red-500 hover:bg-red-50 px-3 py-2 rounded-xl transition-all">
              <LogOut className="w-4 h-4" /> Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-10">

        {/* ── Hero Profile Header ──────────────────────────────── */}
        <div className="relative mb-8 rounded-[32px] overflow-hidden" style={{ background:'linear-gradient(135deg, #14b8a6 0%, #0891b2 60%, #0284c7 100%)' }}>
          {/* decorative grid */}
          <div className="absolute inset-0 opacity-[0.08]"
            style={{ backgroundImage:'linear-gradient(rgba(255,255,255,.6) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.6) 1px,transparent 1px)', backgroundSize:'40px 40px' }} />
          {/* glow orb */}
          <div className="absolute right-0 top-0 w-96 h-96 rounded-full opacity-20" style={{ background:'white', filter:'blur(80px)', transform:'translate(30%,-30%)' }} />

          <div className="relative z-10 px-8 py-8 flex flex-col md:flex-row items-start md:items-center gap-6">
            {/* Avatar */}
            <div className="relative">
              <div className="w-24 h-24 rounded-3xl flex items-center justify-center text-3xl font-black text-white shadow-2xl"
                style={{ background:'rgba(255,255,255,0.2)', border:'3px solid rgba(255,255,255,0.35)', backdropFilter:'blur(10px)' }}>
                {initials}
              </div>
              <button onClick={() => setActiveTab('profile')} className="absolute -bottom-2 -right-2 w-8 h-8 bg-white rounded-xl flex items-center justify-center shadow-lg hover:scale-110 transition-all">
                <Edit3 className="w-3.5 h-3.5 text-teal-600" />
              </button>
            </div>

            {/* Name & meta */}
            <div className="flex-1">
              <div className="flex items-center gap-3 mb-1">
                <h1 className="text-2xl md:text-3xl font-black text-white">{displayName}</h1>
                <span className="text-xs font-bold bg-white/20 text-white px-2.5 py-1 rounded-full border border-white/30">
                  ✦ Member
                </span>
              </div>
              <p className="text-teal-100 text-sm mb-4">{profileData.email}</p>
              {/* Quick stats strip */}
              <div className="flex flex-wrap gap-4">
                {[
                  { label:'Orders', value: orders.length, icon:'📦' },
                  { label:'Addresses', value: profileData.addresses?.length||0, icon:'📍' },
                  { label:'Cart Items', value: cart.length, icon:'🛒' },
                  { label:'Total Spent', value: `₹${totalSpent.toLocaleString()}`, icon:'💳' },
                ].map((s,i) => (
                  <div key={i} className="flex items-center gap-2 bg-white/15 backdrop-blur-sm px-3 py-1.5 rounded-xl border border-white/20">
                    <span className="text-base">{s.icon}</span>
                    <div>
                      <p className="text-[10px] text-teal-100 font-semibold leading-none">{s.label}</p>
                      <p className="text-sm font-black text-white leading-tight">{s.value}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Quick actions */}
            <div className="flex flex-col gap-2 shrink-0">
              <button onClick={() => setCurrentPage('products')}
                className="flex items-center gap-2 px-5 py-2.5 bg-white font-black text-sm rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl text-teal-700">
                <ShoppingBag className="w-4 h-4" /> Shop Now
              </button>
              <button onClick={() => setCurrentPage('orders')}
                className="flex items-center gap-2 px-5 py-2.5 bg-white/15 hover:bg-white/25 font-bold text-sm rounded-2xl text-white transition-all border border-white/20">
                <Package className="w-4 h-4" /> My Orders
              </button>
            </div>
          </div>
        </div>

        {/* ── Tab Nav ──────────────────────────────────────────── */}
        <div className="flex gap-2 mb-6 bg-white rounded-2xl p-1.5 border border-gray-100 shadow-sm w-fit">
          {tabs.map(tab => {
            const Icon = tab.icon;
            return (
              <button key={tab.id} onClick={() => setActiveTab(tab.id)}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold transition-all ${
                  activeTab===tab.id
                    ? 'bg-gradient-to-r from-teal-500 to-cyan-600 text-white shadow-md shadow-cyan-200/40'
                    : 'text-slate-500 hover:text-teal-600 hover:bg-teal-50'
                }`}>
                <Icon className="w-4 h-4" />
                {tab.label}
              </button>
            );
          })}
        </div>

        {/* ── TAB: Profile ─────────────────────────────────────── */}
        {activeTab === 'profile' && (
          <div className="grid lg:grid-cols-3 gap-6" style={{ animation:'fadeIn .4s ease both' }}>
            {/* Personal info card */}
            <div className="lg:col-span-2 bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
              <div className="px-8 py-5 border-b border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-2xl flex items-center justify-center bg-gradient-to-br from-teal-500 to-cyan-600">
                    <User className="w-5 h-5 text-white" />
                  </div>
                  <div>
                    <h2 className="font-black text-slate-900">Personal Information</h2>
                    <p className="text-xs text-slate-400 font-medium">Manage your account details</p>
                  </div>
                </div>
                <button
                  onClick={editMode ? handleSaveProfile : () => setEditMode(true)}
                  disabled={savingProfile}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all active:scale-95 ${
                    editMode
                      ? 'bg-gradient-to-r from-emerald-500 to-green-600 text-white shadow-md shadow-green-200/50'
                      : `${PRI}`
                  }`}>
                  {savingProfile ? (
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                  ) : editMode ? (
                    <><Check className="w-4 h-4" /> Save</>
                  ) : (
                    <><Edit3 className="w-4 h-4" /> Edit</>
                  )}
                </button>
              </div>

              <div className="p-8">
                <div className="grid md:grid-cols-2 gap-5">
                  {[
                    { key:'fullName', label:'Full Name', type:'text', disabled: !editMode },
                    { key:'email',    label:'Email Address', type:'email', disabled: true, note:'Cannot be changed' },
                    { key:'mobile',   label:'Mobile Number', type:'tel', disabled: !editMode },
                  ].map(field => (
                    <div key={field.key}>
                      <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">{field.label}</label>
                      <input
                        type={field.type}
                        value={(profileData[field.key]||'').toString()}
                        onChange={e => setProfileData({...profileData, [field.key]: e.target.value})}
                        disabled={field.disabled}
                        className={`w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none ${
                          !field.disabled
                            ? 'border-2 border-teal-200 focus:border-teal-400 focus:ring-4 focus:ring-teal-50 bg-white text-slate-900'
                            : 'border border-gray-100 bg-slate-50 text-slate-500 cursor-not-allowed'
                        }`}
                      />
                      {field.note && <p className="text-[10px] text-slate-400 mt-1 ml-1">✓ {field.note}</p>}
                    </div>
                  ))}

                  {/* Gender */}
                  <div>
                    <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2">Gender</label>
                    <select
                      value={profileData.gender||''}
                      onChange={e => setProfileData({...profileData, gender: e.target.value})}
                      disabled={!editMode}
                      className={`w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none ${
                        editMode
                          ? 'border-2 border-teal-200 focus:border-teal-400 focus:ring-4 focus:ring-teal-50 bg-white text-slate-900'
                          : 'border border-gray-100 bg-slate-50 text-slate-500 cursor-not-allowed'
                      }`}>
                      <option value="">Select Gender (Optional)</option>
                      <option value="Male">👨 Male</option>
                      <option value="Female">👩 Female</option>
                      <option value="Other">🧑 Other</option>
                      <option value="PreferNotToSay">🤐 Prefer Not to Say</option>
                    </select>
                  </div>
                </div>

                {editMode && (
                  <div className="mt-6 pt-6 border-t border-gray-50 flex gap-3">
                    <button onClick={handleSaveProfile} disabled={savingProfile}
                      className="flex-1 py-3 rounded-2xl text-sm font-black bg-gradient-to-r from-emerald-500 to-green-600 text-white shadow-md hover:shadow-lg hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50 flex items-center justify-center gap-2">
                      {savingProfile ? <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /> Saving...</> : <><Check className="w-4 h-4" /> Save Changes</>}
                    </button>
                    <button onClick={() => { setEditMode(false); fetchProfile(); }}
                      className="flex-1 py-3 rounded-2xl text-sm font-bold text-slate-600 bg-slate-100 hover:bg-slate-200 active:scale-95 transition-all">
                      <X className="w-4 h-4 inline mr-1" /> Cancel
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* Sidebar — account stats + quick actions */}
            <div className="space-y-4">
              {/* Stats */}
              <div className="bg-white rounded-3xl border border-gray-100 shadow-sm p-6">
                <h3 className="font-black text-slate-900 mb-4 flex items-center gap-2">
                  <TrendingUp className="w-5 h-5 text-teal-500" /> Account Stats
                </h3>
                <div className="space-y-3">
                  {[
                    { label:'Total Orders', value: orders.length, color:'from-teal-50 to-cyan-50', border:'border-teal-100', text:'text-teal-700', icon: Package },
                    { label:'Saved Addresses', value: profileData.addresses?.length||0, color:'from-violet-50 to-purple-50', border:'border-violet-100', text:'text-violet-700', icon: MapPin },
                    { label:'Cart Items', value: cart.length, color:'from-orange-50 to-amber-50', border:'border-orange-100', text:'text-orange-700', icon: ShoppingCart },
                    { label:'Total Spent', value: `₹${totalSpent.toLocaleString()}`, color:'from-emerald-50 to-green-50', border:'border-emerald-100', text:'text-emerald-700', icon: Zap },
                  ].map((s,i) => {
                    const Icon = s.icon;
                    return (
                      <div key={i} className={`flex items-center justify-between p-3.5 rounded-2xl bg-gradient-to-r ${s.color} border ${s.border}`}>
                        <div className="flex items-center gap-3">
                          <Icon className={`w-5 h-5 ${s.text} opacity-60`} />
                          <p className="text-sm text-slate-600 font-semibold">{s.label}</p>
                        </div>
                        <p className={`text-lg font-black ${s.text}`}>{s.value}</p>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Quick Actions */}
              <div className="bg-white rounded-3xl border border-gray-100 shadow-sm p-6">
                <h3 className="font-black text-slate-900 mb-4">Quick Actions</h3>
                <div className="space-y-2">
                  {[
                    { label:'Continue Shopping', page:'products', icon: ShoppingBag, style: PRI },
                    { label:'View All Orders', page:'orders', icon: Package, style:'bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white font-semibold transition-all shadow-md hover:shadow-purple-200/50 active:scale-95' },
                    { label:'View Cart', page:'cart', icon: ShoppingCart, style:'bg-gradient-to-r from-emerald-500 to-green-600 hover:from-emerald-600 hover:to-green-700 text-white font-semibold transition-all shadow-md hover:shadow-green-200/50 active:scale-95' },
                  ].map((a,i) => {
                    const Icon = a.icon;
                    return (
                      <button key={i} onClick={() => setCurrentPage(a.page)}
                        className={`w-full flex items-center justify-between px-4 py-3 rounded-2xl text-sm ${a.style}`}>
                        <div className="flex items-center gap-2">
                          <Icon className="w-4 h-4" /> {a.label}
                        </div>
                        <ArrowRight className="w-4 h-4" />
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ── TAB: Addresses ───────────────────────────────────── */}
        {activeTab === 'addresses' && (
          <div style={{ animation:'fadeIn .4s ease both' }}>
            <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
              <div className="px-8 py-5 border-b border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-2xl flex items-center justify-center bg-gradient-to-br from-violet-500 to-purple-600">
                    <MapPin className="w-5 h-5 text-white" />
                  </div>
                  <div>
                    <h2 className="font-black text-slate-900">Saved Addresses</h2>
                    <p className="text-xs text-slate-400 font-medium">{profileData.addresses?.length||0} addresses saved</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => setShowAddressModal(true)} className={`${PRI} flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm`}>
                    <Plus className="w-4 h-4" /> Add Address
                  </button>
                  {profileData.addresses?.length > 0 && (
                    <button
                      onClick={async () => {
                                                try { for (const a of profileData.addresses) await addressAPI.remove(a.id); await fetchAddresses(); }
                        catch { setError('Failed to delete addresses'); }
                      }}
                      className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-bold text-red-500 bg-red-50 hover:bg-red-100 border border-red-100 transition-all active:scale-95">
                      <Trash2 className="w-4 h-4" /> Clear All
                    </button>
                  )}
                </div>
              </div>

              <div className="p-8">
                {!profileData.addresses?.length ? (
                  <div className="text-center py-16">
                    <div className="w-20 h-20 bg-teal-50 rounded-3xl flex items-center justify-center mx-auto mb-4">
                      <MapPin className="w-9 h-9 text-teal-300" />
                    </div>
                    <h3 className="text-lg font-black text-slate-900 mb-2">No addresses yet</h3>
                    <p className="text-slate-500 text-sm mb-6">Add your first delivery address</p>
                    <button onClick={() => setShowAddressModal(true)} className={`${PRI} px-6 py-2.5 rounded-xl text-sm`}>
                      <Plus className="w-4 h-4 inline mr-1" /> Add Address
                    </button>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                    {profileData.addresses.map((addr, idx) => (
                      <div key={addr.id}
                        className="relative p-5 rounded-2xl border-2 transition-all hover:border-teal-200 hover:shadow-lg hover:shadow-teal-50 group"
                        style={{ borderColor: addr.IsDefault ? 'rgba(20,184,166,0.4)' : '#f1f5f9', background: addr.IsDefault ? 'linear-gradient(135deg, #f0fdfa, #ecfeff)' : 'white' }}>
                        {/* Default badge */}
                        {addr.IsDefault && (
                          <span className="absolute top-3 right-10 text-[10px] font-black text-teal-700 bg-teal-100 px-2.5 py-1 rounded-full border border-teal-200">
                            ⭐ Default
                          </span>
                        )}
                        <button onClick={() => removeAddress(addr.id)}
                          className="absolute top-3 right-3 w-7 h-7 flex items-center justify-center rounded-xl text-slate-300 hover:text-red-500 hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100">
                          <Trash2 className="w-3.5 h-3.5" />
                        </button>

                        {/* Label icon */}
                        <div className="w-10 h-10 rounded-2xl flex items-center justify-center mb-3 bg-gradient-to-br from-teal-500 to-cyan-600">
                          <MapPin className="w-5 h-5 text-white" />
                        </div>
                        <p className="font-black text-slate-900 mb-1">{addr.label||`Address ${idx+1}`}</p>
                        <p className="text-sm text-slate-500 leading-relaxed">
